prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?org WHERE {
  ?model a bboExt:Model .
  ?model tai:normalizedId "01e9c28ede6a4695b91dd90b3e0c5f1b" .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:belongsTo ?org . ?org bbo:name ?orgName . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?modelId ?origId ?normId WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model bbo:id ?modelId . }
  OPTIONAL { ?model tai:originalId ?origId . }
  OPTIONAL { ?model tai:normalizedId ?normId . }
  FILTER(CONTAINS(LCASE(STR(?modelId)), "01e9c28ede6a4695b91dd90b3e0c5f1b") || 
         CONTAINS(LCASE(STR(?origId)), "01e9c28ede6a4695b91dd90b3e0c5f1b") ||
         CONTAINS(LCASE(STR(?normId)), "01e9c28ede6a4695b91dd90b3e0c5f1b"))
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?task ?taskName ?msgFlow ?msgRef ?sourceRef ?targetRef WHERE {
  ?model a bboExt:Model .
  ?model tai:originalId "01e9c28ede6a4695b91dd90b3e0c5f1b" .
  ?def tai:belongsTo ?model .
  ?choreo tai:belongsTo ?def .
  ?task a bboExt:ChoreographyTask .
  ?task tai:belongsTo ?choreo .
  OPTIONAL { ?task bbo:name ?taskName . }
  OPTIONAL { 
    ?msgFlow a bboExt:MessageFlow .
    ?msgFlow tai:belongsTo ?choreo .
    OPTIONAL { ?msgFlow bboExt:messageRef ?msgRef . }
    OPTIONAL { ?msgFlow bboExt:sourceRef ?sourceRef . }
    OPTIONAL { ?msgFlow bboExt:targetRef ?targetRef . }
  }
}
LIMIT 50

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
